# HELPER FUNCTIONS
################################################################################
#' Suppress plot-related warnings, messages, and graphics output (testing utility)
#'
#' Internal helper used in unit tests to silence warnings, messages, and
#' graphics output generated by plotting functions. Prevents creation of
#' Rplots.pdf and other unwanted plot files during testing.
#'
#' @param expr An R expression to evaluate.
#'
#' @return The result of evaluating \code{expr}, with warnings, messages,
#'   and graphics output suppressed.
#'
#' @keywords internal
suppress_plot_warnings <- function(expr) {
  # Store original working directory
  orig_wd <- getwd()

  # Create temporary directory for any file outputs
  temp_dir <- tempdir()
  temp_test_dir <- file.path(temp_dir, paste0("ninetails_test_", Sys.getpid()))
  dir.create(temp_test_dir, showWarnings = FALSE, recursive = TRUE)

  # Ensure cleanup happens even if expr fails
  on.exit({
    # Reset working directory
    setwd(orig_wd)

    # Clean up any graphics devices we may have opened
    while(length(grDevices::dev.list()) > 0) {
      try(grDevices::dev.off(), silent = TRUE)
    }

    # Remove temporary test directory
    unlink(temp_test_dir, recursive = TRUE, force = TRUE)
  }, add = TRUE)

  # Change to temporary directory to catch any file outputs
  setwd(temp_test_dir)

  # Open a null graphics device to capture plot output
  grDevices::png(filename = file.path(temp_test_dir, "null_plot.png"),
                 width = 1, height = 1)

  # Execute expression with all output suppressed
  result <- suppressWarnings(suppressMessages(expr))

  return(result)
}


#' Generate dummy nanopolish_qc summary data (testing utility)
#'
#' Internal helper function used in unit tests to create synthetic
#' QC summary tables. Produces either aggregated or per-sample
#' dummy read counts across predefined QC categories.
#'
#' @param grouped Logical. If \code{FALSE}, returns an aggregated
#'   summary table. If \code{TRUE}, returns per-sample summaries.
#'
#' @return A \code{data.frame} containing QC tags and dummy read counts.
#'
#' @keywords internal
create_test_processing_info <- function(grouped = FALSE) {
  qc_tags <- c("PASS",
               "ADAPTER",
               "SUFFCLIP",
               "NOREGION",
               "READ_FAILED_LOAD")

  if (!grouped) {
    data.frame(qc_tag = qc_tags,
               n = c(500, 50, 30, 15, 5),
               stringsAsFactors = FALSE)
  } else {
    rbind(
      data.frame(sample_name = "WT_1",
                 qc_tag = qc_tags,
                 n = c(250, 25, 15, 8, 2),
                 stringsAsFactors = FALSE),
      data.frame(sample_name = "KO_1",
                 qc_tag = qc_tags,
                 n = c(300, 30, 20, 10, 4),
                 stringsAsFactors = FALSE)
    )
  }
}


#' Create minimal class_data (QCF variant)
#'
#' Generates a test data frame mimicking a Guppy/nanopolish pipeline
#' with QCF reads, without BAC or UNM annotations.
#'
#' @param grouped Logical; if TRUE, adds a `sample_name` column
#'   splitting reads into WT and KO groups.
#'
#' @return A data.frame containing simulated read classification data.
#'
#' @keywords internal
# Guppy/nanopolish pipeline: has QCF, no BAC, no UNM
make_class_data_qcf <- function(grouped = FALSE) {

  base <- data.frame(readname = paste0("read_", 1:6),
                     contig = "beta_gal",
                     polya_length = c(50, 30, 8, 45, 20, 55),
                     qc_tag = c("PASS", "PASS", "PASS", "PASS", "PASS", "ADAPTER"),
                     class = c("decorated", "blank", "unclassified", "blank",
                              "unclassified", "unclassified"),
                     comments = c("YAY", "MAU", "IRL", "MPU", "MPU", "QCF"),
                     stringsAsFactors = FALSE)

  if (grouped) {
    base$sample_name <- c(rep("WT", 3), rep("KO", 3))
  }
  base
}


