#' Create class_data with decorated/blank/unclassified classes
#'
#' Generates a test data frame containing balanced examples of
#' "decorated", "blank", and "unclassified" read classes.
#'
#' @param grouped Logical; if TRUE, adds a `sample_name` column
#'   splitting reads into WT and KO groups.
#'
#' @return A data.frame containing simulated read classification data.
#'
#' @keywords internal
# class_data with decorated/blank/unclassified class values (for type="A")
make_class_data_decorated <- function(grouped = FALSE) {
  base <- data.frame(readname= paste0("read_", 1:9),
                     contig = "beta_gal",
                     polya_length = c(50, 30, 8, 45, 20, 55, 60, 35, 70),
                     qc_tag = rep("PASS", 9),
                     class = c("decorated", "decorated", "decorated",
                              "blank", "blank", "blank","unclassified",
                              "unclassified", "unclassified"),
                     comments = c("YAY", "YAY", "YAY","MAU", "MAU",
                                 "MPU","IRL", "QCF", "IRL"),
                     stringsAsFactors = FALSE)

  if (grouped) {
    base$sample_name <- c(rep("WT", 5), rep("KO", 4))
  }
  base
}


# Prevent testthat from creating snapshots and other artifacts
old_opts <- options(
  testthat.default_check_reporter = "silent",
  testthat.use_colour = FALSE,
  warn = -1  # Suppress all warnings during testing
)

# Ensure we restore options when done
withr::defer(options(old_opts), testthat::teardown_env())

# Set working directory to a temporary location for the duration of tests
test_temp_dir <- file.path(tempdir(), "ninetails_tests")
dir.create(test_temp_dir, showWarnings = FALSE, recursive = TRUE)
old_wd <- setwd(test_temp_dir)
withr::defer(setwd(old_wd), testthat::teardown_env())

# Clean up function to remove any stray files
cleanup_test_files <- function() {
  # Remove common plot artifacts
  files_to_remove <- c("Rplots.pdf", "Rplot.pdf", "_snaps")
  for(f in files_to_remove) {
    if(file.exists(f)) unlink(f, recursive = TRUE, force = TRUE)
    # Also check in original directory
    orig_path <- file.path(old_wd, f)
    if(file.exists(orig_path)) unlink(orig_path, recursive = TRUE, force = TRUE)
  }
}

# Run cleanup after all tests
withr::defer(cleanup_test_files(), testthat::teardown_env())

